function solve(s: string, order: number[], k: number): number {
    const n: number = s.length;
    const replaced: number[] = new Array(n).fill(0);

    // Preprocess the order to know which positions are replaced at each time step
    const replaceAt: number[] = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        replaceAt[order[i]] = i;
    }

    // Function to calculate the number of valid substrings
    function countValidSubstrings(): number {
        let count: number = 0;
        const stars: number[] = [];

        // Find all positions with '*' (replaced)
        for (let i = 0; i < n; i++) {
            if (replaced[i]) {
                stars.push(i);
            }
        }

        // For each star, calculate how many substrings include it
        for (let i = 0; i < stars.length; i++) {
            const star = stars[i];
            // Number of substrings that include this star
            // = (number of left choices) * (number of right choices)
            const left = star + 1;
            const right = n - star;
            count += left * right;
        }

        return count;
    }

    // Binary search for the minimum time t
    let left: number = 0;
    let right: number = n;
    let answer: number = -1;

    while (left < right) {
        const mid: number = Math.floor((left + right) / 2);
        // Replace first mid elements in order
        for (let i = 0; i < mid; i++) {
            const pos: number = order[i];
            if (!replaced[pos]) {
                replaced[pos] = 1;
            }
        }

        const validCount: number = countValidSubstrings();
        if (validCount >= k) {
            answer = mid;
            right = mid;
        } else {
            left = mid + 1;
        }

        // Reset replaced array for next iteration
        for (let i = 0; i < n; i++) {
            replaced[i] = 0;
        }
    }

    return answer;
}

